results.pred_mql:
db.transactions.aggregate([
  { $unwind: "$transactions" },
  {
    $match: {
      "transactions.date": {
        $gte: ISODate("2014-01-01"),
        $lte: ISODate("2016-12-31")
      }
    }
  },
  {
    $group: {
      _id: "$account_id",
      total_transactions: { $sum: 1 }
    }
  },
  { $sort: { total_transactions: -1 } },
  { $limit: 5 },
  {
    $project: {
      _id: 0,
      account_id: "$_id",
      total_transactions: 1
    }
  }
])

